import numpy as np

def calculate_distance(pos1, pos2):
    return np.linalg.norm(pos1 - pos2)

def calculate_time(pos1, pos2, speed):
    return calculate_distance(pos1, pos2) / speed

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    min_cost = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_time(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        else:
            wait_time = 0

        time_window_penalty = max(0, arrival_time - end_window) * 10  # penalty factor for missing a time window

        total_cost = travel_time + wait_time + time_window_penalty

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = i

    if best_node is not None:
        best_arrival_time = calculate_time(cur_truck_pos, unvisited_customers[best_node], truck_speed) + current_time
        if best_arrival_time < time_windows[best_node][0]:
            wait_duration = time_windows[best_node][0] - best_arrival_time
            if min_cost > wait_duration:
                best_node = None

    return best_node

import numpy as np

def euclidean_distance(point1, point2):
    return np.linalg.norm(point1 - point2)

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_cost = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        distance = euclidean_distance(cur_truck_pos, customer_pos)
        arrival_time = current_time + (distance / truck_speed)
        start_window, end_window = time_windows[idx]

        if arrival_time > end_window:
            # If we can't meet the time window
            continue

        wait_time = max(0, start_window - arrival_time)
        total_time = arrival_time + wait_time + euclidean_distance(customer_pos, depot_pos) / truck_speed

        cost = total_time

        if cost < min_cost:
            min_cost = cost
            best_node = idx

    return best_node
